'use client'

import { use, useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { Hairline } from '@/components/builder/hairline'
import { StepSheet } from '@/components/builder/step-sheet'
import { useBuilder } from '@/components/builder/builder-provider'
import { euros } from '@/lib/builder/api'

export default function ExtrasPage({ params }: { params: Promise<{ inviteId: string }> }) {
  const { inviteId } = use(params)
  const { invite, extrasCatalog, inviteExtras, toggleExtra, patchDraft } = useBuilder()
  const router = useRouter()
  const [notes, setNotes] = useState('')

  useEffect(() => {
    if (invite?.additional_notes) setNotes(invite.additional_notes)
  }, [invite])

  const isEnabled = (extraId: string) =>
    inviteExtras.some(e => e.extra_id === extraId)

  const handleContinue = () => {
    const currentNotes = invite?.additional_notes ?? ''
    if (notes !== currentNotes) {
      patchDraft({ additional_notes: notes })
    }
    router.push(`/builder/${inviteId}/review`)
  }

  return (
    <>
      <Hairline step="extras" />
      <StepSheet
        title="Finishing touches"
        lede="Optional add-ons to make your invitation even more seamless."
        primaryLabel="Continue"
        onPrimary={handleContinue}
        backHref={`/builder/${inviteId}/details`}
      >
        {extrasCatalog.length === 0 ? (
          <div className="flex flex-col gap-3">
            {['Custom domain', 'RSVP tracking', 'Password protection'].map((name) => (
              <div
                key={name}
                className="flex items-center justify-between rounded-2xl px-4 py-4 opacity-40"
                style={{ background: 'rgba(255,255,255,0.5)', border: '1px dashed rgba(26,24,22,0.1)' }}
              >
                <span className="font-cormorant font-light" style={{ fontSize: 16, color: '#1A1816' }}>{name}</span>
                <span className="font-inter rounded-full px-2 py-0.5" style={{ fontSize: 10, color: 'rgba(26,24,22,0.4)', background: 'rgba(26,24,22,0.05)' }}>Coming soon</span>
              </div>
            ))}
          </div>
        ) : (
          <div className="flex flex-col gap-2.5">
            {extrasCatalog.map(item => {
              const on = isEnabled(item.id)
              return (
                <button
                  key={item.id}
                  type="button"
                  onClick={() => void toggleExtra(item)}
                  aria-pressed={on}
                  className="flex items-center justify-between rounded-2xl px-4 py-4 text-left transition-all"
                  style={{
                    background: on ? 'rgba(168,133,75,0.09)' : 'rgba(255,255,255,0.5)',
                    border: on
                      ? '1px solid rgba(168,133,75,0.38)'
                      : '1px solid rgba(26,24,22,0.08)',
                  }}
                >
                  <div className="flex flex-col gap-0.5">
                    <span
                      className="font-cormorant font-light"
                      style={{ fontSize: 16, color: '#1A1816' }}
                    >
                      {item.name}
                    </span>
                    <span className="font-inter" style={{ fontSize: 11, color: 'rgba(26,24,22,0.44)' }}>
                      {euros(item.price_cents)}
                    </span>
                  </div>

                  {/* Toggle indicator */}
                  <span
                    className="flex-none flex items-center justify-center rounded-full transition-all"
                    style={{
                      width: 22,
                      height: 22,
                      background: on ? '#A8854B' : 'transparent',
                      border: on ? 'none' : '1.5px solid rgba(26,24,22,0.2)',
                    }}
                    aria-hidden="true"
                  >
                    {on && (
                      <svg width="10" height="10" viewBox="0 0 10 10" fill="none">
                        <path
                          d="M2 5.5l2 2 4-4"
                          stroke="#FDFCF9"
                          strokeWidth="1.3"
                          strokeLinecap="round"
                          strokeLinejoin="round"
                        />
                      </svg>
                    )}
                  </span>
                </button>
              )
            })}
          </div>
        )}

        {/* Additional notes */}
        <div className="mt-5 flex flex-col gap-1.5">
          <span
            className="font-inter uppercase"
            style={{ fontSize: 9, letterSpacing: '0.1em', color: 'rgba(26,24,22,0.44)' }}
          >
            Any notes for us?
          </span>
          <textarea
            value={notes}
            onChange={e => setNotes(e.target.value)}
            placeholder="Special requests, accessibility needs, a note to our team…"
            rows={3}
            className="w-full resize-none rounded-xl bg-white/60 px-3.5 py-3 font-inter text-sm text-[#1A1816] placeholder:text-[#1A1816]/28 outline-none transition-colors"
            style={{ border: '1px solid rgba(26,24,22,0.12)' }}
            onFocus={e => (e.currentTarget.style.borderColor = 'rgba(168,133,75,0.5)')}
            onBlur={e => (e.currentTarget.style.borderColor = 'rgba(26,24,22,0.12)')}
          />
        </div>
      </StepSheet>
    </>
  )
}
